1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single living cell (no neighbors, underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells that each have only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a cell alive that has exactly 2 live neighbors (survival)", () => {
18	    // Horizontal blinker: center cell (1,0) has 2 neighbors → survives
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("should keep a cell alive that has exactly 3 live neighbors (survival)", () => {
23	    // T-shape: cell (1,0) has 3 neighbors: (0,0), (2,0), (1,1) → survives
24	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
25	    expect(result).toContainEqual([1, 0]);
26	  });
27	  it("should kill a cell that has 4 or more live neighbors (overpopulation)", () => {
28	    // Plus/cross shape: center cell (1,1) has 4 neighbors → dies
29	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
33	    // L-shape: (0,2), (1,2), (0,1)
34	    // Dead cell (1,1) has exactly 3 live neighbors → becomes alive
35	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
36	    expect(result).toContainEqual([1, 1]);
37	  });
38	  it.todo("should preserve a block still life across a generation");
39	  it.todo("should oscillate a blinker to its alternate phase");
40	});
41

1	export type Cell = [number, number];
2	
3	function cellKey(x: number, y: number): string {
4	  return `${x},${y}`;
5	}
6	
7	function countLiveNeighbors(cell: Cell, liveSet: Set<string>): number {
8	  const [x, y] = cell;
9	  let count = 0;
10	  for (let dx = -1; dx <= 1; dx++) {
11	    for (let dy = -1; dy <= 1; dy++) {
12	      if (dx === 0 && dy === 0) continue;
13	      if (liveSet.has(cellKey(x + dx, y + dy))) count++;
14	    }
15	  }
16	  return count;
17	}
18	
19	export function nextGeneration(liveCells: Cell[]): Cell[] {
20	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
21	
22	  const survivors = liveCells.filter(
23	    (cell) => {
24	      const neighborCount = countLiveNeighbors(cell, liveSet);
25	      return neighborCount === 2 || neighborCount === 3;
26	    }
27	  );
28	
29	  const deadCandidates = new Map<string, Cell>();
30	  for (const [x, y] of liveCells) {
31	    for (let dx = -1; dx <= 1; dx++) {
32	      for (let dy = -1; dy <= 1; dy++) {
33	        if (dx === 0 && dy === 0) continue;
34	        const key = cellKey(x + dx, y + dy);
35	        if (!liveSet.has(key)) {
36	          deadCandidates.set(key, [x + dx, y + dy]);
37	        }
38	      }
39	    }
40	  }
41	
42	  const births = [...deadCandidates.values()].filter(
43	    (cell) => countLiveNeighbors(cell, liveSet) === 3
44	  );
45	
46	  return [...survivors, ...births];
47	}
